const phrases = [
  "Xin chào người đẹp, có hợp đồng nè",
  "Hú hú, hợp đồng tới đây",
  "Hợp đồng cái qq gì nhiều dãy",
  "Tới giờ nữa rồi đó, hợp đồng tới rồi đó",
  "Hợp đồng nữa, vỡn hẻ",
  "Uống nước, uống nước rồi làm hợp đồng nè",
  "Làm hợp đồng rồi nghĩ cách tiêu hết xiền nè người đẹp",
  "Ẻn Ẻn, hợp đồng tới đây"
];

const randomIndex = Math.floor(Math.random() * phrases.length);

return [
  {
    json: {
      phrase: phrases[randomIndex]
    }
  }
];

// Lấy text từ node "Loop Over Items"
const text = $('Loop Over Items').first().json.text || '';

// Tìm chuỗi 14 chữ số liên tiếp
const match = text.match(/\d{14}/);

// Trả kết quả
return [
  {
    json: {
      result: match ? match[0] : "Không có mã đơn hàng"
    }
  }
];

